solution_code:
#include <iostream>

inline const int kFahrenheitOffset = 32;

int celsiusToFahrenheit(int c) {
    return c * 9 / 5 + kFahrenheitOffset;
}

int main() {
    int celsius;
    std::cin >> celsius;
    std::cout << celsiusToFahrenheit(celsius) << "\n";
    return 0;
}
